@module trackerPage  src=trackerPage.lua  loc=1420  sha=69f289a  mode=chunk
@deps cm, cmgr, chrome, gui

# Invariants & contracts
  @invariant  page is render + input only; tracker state lives in vm/ec/tm — never cached here
  @invariant  cm/vm read fresh each frame; only ephemeral UI state persists across frames (gridX/Y, dragging, modalState, picker*, laneConsumed)
  @invariant  col.x == nil is the visibility predicate; every per-column draw must gate on it
  @invariant  cell coordinates are 0-indexed; header rows at -HEADER, row-number gutter at -GUTTER
  @invariant  writes go through vm or cmgr commands — page never reaches into tm

# Shapes
  @shape  ToolbarSegment = { id, render = fn(), visible? = fn() -> bool }
  @shape  modalState = { title, prompt, callback, buf, kind?='confirm'|'takeProps', nameBuf?, rowsBuf?, rowsGen?, mode?, refocusRows? }
  @shape  focusState = { suppressKbd:bool, acceptCmds:bool }

# Imports
  @require util = 'util'  @ 8
  @require timing = 'timing'  @ 9
  @require tuning = 'tuning'  @ 10
  @require regions = 'regions'  @ 11
  @require ImGui = 'imgui'  @ 17

# Constructed sub-instances
  @construct mm          = util.instantiate('midiManager')  @ 26
  @construct tm          = util.instantiate('trackerManager')  @ 27
  @construct vm          = util.instantiate('trackerView')  @ 28
  @construct seqMgr      = util.instantiate('sequenceManager')  @ 29
  @construct swingEditor = util.instantiate('swingEditor')  @ 68
  @construct curveEd     = util.instantiate('curveEditor')  @ 70

# Private state
  @state GUTTER = 5  @ 33   -- in grid chars: 3-char row num + spacer + region slot
  @state HEADER = 3  @ 34   -- in grid rows
